create extension if not exists pgcrypto;
create table business_unit (business_unit_id uuid primary key default gen_random_uuid(), name text not null, parent_business_unit_id uuid, country_code char(2), is_active boolean default true);
create table collaborator (collaborator_id uuid primary key default gen_random_uuid(), employee_number text unique not null, email text unique not null, display_name text not null, business_unit_id uuid references business_unit, manager_id uuid references collaborator, employment_status text not null, source_system text not null);
create table vendor (vendor_id uuid primary key default gen_random_uuid(), name text unique not null, website_url text, is_active boolean default true);
create table certification (certification_id uuid primary key default gen_random_uuid(), vendor_id uuid references vendor not null, code text, name text not null, category text not null, level text, validity_months int, requires_evidence boolean default true, is_active boolean default true, unique(vendor_id,name));
create table professional_role (professional_role_id uuid primary key default gen_random_uuid(), name text unique not null, is_active boolean default true);
create table role_certification_requirement (requirement_id uuid primary key default gen_random_uuid(), professional_role_id uuid references professional_role, certification_id uuid references certification, requirement_type text not null, priority text not null, is_active boolean default true);
create table certification_assignment (assignment_id uuid primary key default gen_random_uuid(), assignee_id uuid references collaborator not null, certification_id uuid references certification not null, assigned_by uuid references collaborator, due_date date, priority text not null, status text not null, source text not null, reason text, created_at timestamptz default now());
create table migration_batch (migration_batch_id uuid primary key default gen_random_uuid(), source_system text not null, status text not null, started_at timestamptz default now());
create table certification_record (record_id uuid primary key default gen_random_uuid(), collaborator_id uuid references collaborator not null, certification_id uuid references certification not null, assignment_id uuid references certification_assignment, credential_id text, issue_date date not null, expiration_date date, status text not null, validation_status text not null, evidence_required boolean default true, source_system text not null, migration_batch_id uuid references migration_batch, created_at timestamptz default now(), constraint chk_record_dates check (expiration_date is null or expiration_date >= issue_date));
create table evidence_document (evidence_id uuid primary key default gen_random_uuid(), record_id uuid references certification_record not null, storage_uri text not null, classification text not null, uploaded_by uuid references collaborator, uploaded_at timestamptz default now());
create table validation_event (validation_event_id uuid primary key default gen_random_uuid(), record_id uuid references certification_record, validator_id uuid references collaborator, decision text not null, reason text, decided_at timestamptz default now());
create table exception_waiver (waiver_id uuid primary key default gen_random_uuid(), collaborator_id uuid references collaborator, certification_id uuid references certification, approved_by uuid references collaborator, reason text not null, valid_from date, valid_to date, status text not null);
create table notification (notification_id uuid primary key default gen_random_uuid(), recipient_id uuid references collaborator, notification_type text, related_entity_type text, related_entity_id uuid, channel text, status text, created_at timestamptz default now());
create table data_quality_issue (issue_id uuid primary key default gen_random_uuid(), rule_id text, severity text, entity_type text, entity_id uuid, description text, status text, detected_at timestamptz default now());
create table audit_log (audit_id uuid primary key default gen_random_uuid(), correlation_id uuid, actor_id text, actor_type text, action text, entity_type text, entity_id uuid, occurred_at timestamptz default now(), before_data jsonb, after_data jsonb);
create table ai_conversation (conversation_id uuid primary key default gen_random_uuid(), user_id text, channel text, started_at timestamptz default now(), retention_until date);
create table ai_tool_invocation (invocation_id uuid primary key default gen_random_uuid(), conversation_id uuid references ai_conversation, correlation_id uuid, tool_name text, parameters_minimized jsonb, result_status text, result_summary text, created_at timestamptz default now());
